const express = require('express');
const router = express.Router();
const ChatController = require('../controllers/chatController');
const { authenticateToken } = require('../middleware/auth');

// 所有路由都需要认证
router.use(authenticateToken);

// 发送消息
router.post('/send', ChatController.sendMessage);

// 获取频道消息
router.get('/channel/:channelType/:channelId', ChatController.getChannelMessages);

// 获取私聊消息
router.get('/private/:userId', ChatController.getPrivateMessages);

// 获取未读消息
router.get('/unread/:channelType/:channelId', ChatController.getUnreadMessages);

// 标记消息为已读
router.post('/mark-read', ChatController.markAsRead);

// 删除消息
router.delete('/message/:messageId', ChatController.deleteMessage);

// 搜索消息
router.get('/search', ChatController.searchMessages);

module.exports = router;
